You must provide either the source 'file' (-f|--file) or 'url' (-u|--url)

Usage: PolyglotDataStudio.GraphQL.CLI.exe [OPTIONS]
Generate C# GraphQL classes from a source schema file or url for use with the PolyglotDataStudio.GraphQL parsing library.

Options:
  -f, --file=VALUE           [Optional] The schema file to be imported
  -u, --url=VALUE            [Optional] The url from which to get the schema
  -h, --headers=VALUE        [Optional] Additional headers to send that are
                               required by the URL. Provide as a JSON object.
                               Use [$prompt:prompt_title] to get a prompt at
                               runtime.
  -n, --namespace=VALUE      The target namespace for generated files
  -o, --outputDir=VALUE      The target directory for generated files
      --public               Set access modifiers to 'public' instead of '
                               internal' (default)
      --force                Overwrite any files in the target directory
  -?, --help                 show this message and exit

To generate a schema file, use the SDL document if available, or use the following introspection query and save the result to a JSON file.

query IntrospectionQuery {
	__schema {
		queryType { name }
		mutationType { name }
		subscriptionType { name }
		types { ...FullType }
		directives { name description locations args { ...InputValue } }
	}
}
fragment FullType on __Type {
	kind name description
	fields(includeDeprecated: true) {
		name description isDeprecated deprecationReason
		args { ...InputValue }
		type { ...TypeRef }
	}
	inputFields { ...InputValue }
	interfaces { ...TypeRef }
	enumValues(includeDeprecated: true) {
		name description isDeprecated deprecationReason
	}
	possibleTypes { ...TypeRef }
}
fragment InputValue on __InputValue {
	name description type defaultValue
	{ ...TypeRef }
}
fragment TypeRef on __Type { 
	kind name ofType {          # non-null
		kind name ofType {      # list of
			kind name ofType {  # non-null
				kind name       # things
			}
		}
	}
}

